WebSocket 协议是基于 TCP 的一种新的网络协议。实现了浏览器与服务器全双工 (full-duplex) 通信 —— 允许服务器主动发送信息给客户端。http 协议通信只能由客户端发起请求，做不到服务器直接推送消息给客户端。
# Maven 依赖
&lt;dependency&gt;    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;    &lt;artifactId&gt;spring-boot-starter-websocket&lt;/artifactId&gt;    &lt;version&gt;2.1.7.RELEASE&lt;/version&gt;&lt;/dependency&gt;
# WebSocketConfig
import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.web.socket.server.standard.ServerEndpointExporter;/** * @Description: 开启webSocket * @Author: sunfy * @Date: 2020/11/18 上午9:00 */@Configuration  public class WebSocketConfig &#123;  	    @Bean      public ServerEndpointExporter serverEndpointExporter() &#123;          return new ServerEndpointExporter();      &#125;    &#125; 
# WebSocketServer
import com.alibaba.fastjson.JSON;import com.alibaba.fastjson.JSONObject;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Component;import org.springframework.util.StringUtils;import javax.websocket.*;import javax.websocket.server.PathParam;import javax.websocket.server.ServerEndpoint;import java.io.IOException;import java.util.concurrent.ConcurrentHashMap;/** * @Description: 接受客户端连接 * @Author: sunfy * @Date: 2020/11/18 上午9:00 */@ServerEndpoint(&quot;/imserver/&#123;userId&#125;&quot;)@Component@Slf4jpublic class WebSocketServer &#123;    /**     * 静态变量，用来记录当前在线连接数。应该把它设计成线程安全的。     */    private static int onlineCount = 0;    /**     * concurrent包的线程安全Set，用来存放每个客户端对应的MyWebSocket对象。     */    private static ConcurrentHashMap&lt;String, WebSocketServer&gt; webSocketMap = new ConcurrentHashMap&lt;&gt;();    /**     * 与某个客户端的连接会话，需要通过它来给客户端发送数据     */    private Session session;    /**     * 接收userId     */    private String userId = &quot;&quot;;    /**     * @Description: 建立成功后调用的方法     * @Param:     * @return:     * @Author: sunfy     * @Date: 2020/11/18 上午9:02     */    @OnOpen    public void onOpen(Session session, @PathParam(&quot;userId&quot;) String userId) &#123;        this.session = session;        this.userId = userId;        if (webSocketMap.containsKey(userId)) &#123;            webSocketMap.remove(userId);            webSocketMap.put(userId, this);        &#125; else &#123;            webSocketMap.put(userId, this);            // 在线人数            addOnlineCount();        &#125;        log.info(&quot;用户连接:&quot; + userId + &quot;,当前在线人数为:&quot; + getOnlineCount());        try &#123;            sendMessage(&quot;连接成功&quot;);        &#125; catch (IOException e) &#123;            log.error(&quot;用户:&quot; + userId + &quot;,网络异常!!!!!!&quot;);        &#125;    &#125;    /**     * @Description: 连接关闭调用的方法     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:04     */    @OnClose    public void onClose() &#123;        if (webSocketMap.containsKey(userId)) &#123;            //从set中删除            webSocketMap.remove(userId);            subOnlineCount();        &#125;        log.info(&quot;用户退出:&quot; + userId + &quot;,当前在线人数为:&quot; + getOnlineCount());    &#125;    /**     * @description     * @param message 客户端发送过来的消息     * @param session 客户端session     * @return     * @author: sunfy     * @Date: 2020/11/18 上午9:04     */    @OnMessage    public void onMessage(String message, Session session) &#123;        log.info(&quot;用户消息:&quot; + userId + &quot;,报文:&quot; + message);        //可以群发消息        //消息保存到数据库、redis        if (!StringUtils.isEmpty(message)) &#123;            try &#123;                //解析发送的报文                JSONObject jsonObject = JSON.parseObject(message);                //追加发送人(防止串改)                jsonObject.put(&quot;fromUserId&quot;, this.userId);                String toUserId = jsonObject.getString(&quot;toUserId&quot;);                //传送给对应toUserId用户的websocket                if (!StringUtils.isEmpty(toUserId) &amp;&amp; webSocketMap.containsKey(toUserId)) &#123;                    webSocketMap.get(toUserId).sendMessage(jsonObject.toJSONString());                &#125; else &#123;                    log.error(&quot;请求的userId:&quot; + toUserId + &quot;不在该服务器上&quot;);                    //否则不在这个服务器上，发送到mysql或者redis                &#125;            &#125; catch (Exception e) &#123;                e.printStackTrace();            &#125;        &#125;    &#125;    /**     * @Description: 发送消息错误时     * @param session 客户端session     * @param error 错误     * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:07     */    @OnError    public void onError(Session session, Throwable error) &#123;        log.error(&quot;用户错误:&quot; + this.userId + &quot;,原因:&quot; + error.getMessage());        error.printStackTrace();    &#125;    /**     * @Description: 服务器主动推送消息     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:09     */    public void sendMessage(String message) throws IOException &#123;        this.session.getBasicRemote().sendText(message);    &#125;    /**     * @Description: 发送自定义消息     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:10     */    public static void sendInfo(String message, @PathParam(&quot;userId&quot;) String userId) throws IOException &#123;        log.info(&quot;发送消息到:&quot; + userId + &quot;，报文:&quot; + message);        if (!StringUtils.isEmpty(userId) &amp;&amp; webSocketMap.containsKey(userId)) &#123;            webSocketMap.get(userId).sendMessage(message);        &#125; else &#123;            log.error(&quot;用户&quot; + userId + &quot;,不在线！&quot;);        &#125;    &#125;    /**     * @Description: 获取当前在线人数     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:10     */    public static synchronized int getOnlineCount() &#123;        return onlineCount;    &#125;    /**     * @Description: 增加在线人数     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:10     */    public static synchronized void addOnlineCount() &#123;        WebSocketServer.onlineCount++;    &#125;    /**     * @Description: 在线人数减1     * @Param:      * @return:      * @Author: sunfy     * @Date: 2020/11/18 上午9:11     */    public static synchronized void subOnlineCount() &#123;        WebSocketServer.onlineCount--;    &#125;&#125;
