import com.sunfy.config.WebSocketServer;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.PathVariable;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;import org.springframework.web.servlet.ModelAndView;import java.io.IOException;/** * @Description: 测试Controller * @Param:  * @return:  * @Author: sunfy * @Date: 2020/11/18 上午9:13 */@RestControllerpublic class DemoController &#123;    @GetMapping(&quot;index&quot;)    public ResponseEntity&lt;String&gt; index()&#123;        return ResponseEntity.ok(&quot;请求成功&quot;);    &#125;    @GetMapping(&quot;page&quot;)    public ModelAndView page()&#123;        return new ModelAndView(&quot;websocket&quot;);    &#125;    @RequestMapping(&quot;/push/&#123;toUserId&#125;&quot;)    public ResponseEntity&lt;String&gt; pushToWeb(String message, @PathVariable String toUserId) throws IOException &#123;        WebSocketServer.sendInfo(message,toUserId);        return ResponseEntity.ok(&quot;MSG SEND SUCCESS&quot;);    &#125;&#125;
