&lt;!DOCTYPE html&gt;&lt;html&gt;&lt;head&gt;    &lt;meta charset=&quot;utf-8&quot;&gt;    &lt;title&gt;websocket通讯&lt;/title&gt;&lt;/head&gt;&lt;script src=&quot;https://cdn.bootcss.com/jquery/3.3.1/jquery.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    var socket;    function openSocket() &#123;        if (typeof (WebSocket) == &quot;undefined&quot;) &#123;            console.log(&quot;您的浏览器不支持WebSocket&quot;);        &#125; else &#123;            console.log(&quot;您的浏览器支持WebSocket&quot;);            //实现化WebSocket对象，指定要连接的服务器地址与端口  建立连接            //等同于socket = new WebSocket(&quot;ws://localhost:8888/xxxx/im/25&quot;);            //var socketUrl=&quot;$&#123;request.contextPath&#125;/im/&quot;+$(&quot;#userId&quot;).val();            var socketUrl = &quot;http://localhost:8080/imserver/&quot; + $(&quot;#userId&quot;).val();            socketUrl = socketUrl.replace(&quot;https&quot;, &quot;ws&quot;).replace(&quot;http&quot;, &quot;ws&quot;);            console.log(socketUrl);            if (socket != null) &#123;                socket.close();                socket = null;            &#125;            socket = new WebSocket(socketUrl);            //打开事件            socket.onopen = function () &#123;                console.log(&quot;websocket已打开&quot;);                //socket.send(&quot;这是来自客户端的消息&quot; + location.href + new Date());            &#125;;            //获得消息事件            socket.onmessage = function (msg) &#123;                console.log(msg.data);                //发现消息进入    开始处理前端触发逻辑            &#125;;            //关闭事件            socket.onclose = function () &#123;                console.log(&quot;websocket已关闭&quot;);            &#125;;            //发生了错误事件            socket.onerror = function () &#123;                console.log(&quot;websocket发生了错误&quot;);            &#125;        &#125;    &#125;    function sendMessage() &#123;        if (typeof (WebSocket) == &quot;undefined&quot;) &#123;            console.log(&quot;您的浏览器不支持WebSocket&quot;);        &#125; else &#123;            console.log(&quot;您的浏览器支持WebSocket&quot;);            console.log(&#x27;&#123;&quot;toUserId&quot;:&quot;&#x27; + $(&quot;#toUserId&quot;).val() + &#x27;&quot;,&quot;contentText&quot;:&quot;&#x27; + $(&quot;#contentText&quot;).val() + &#x27;&quot;&#125;&#x27;);            socket.send(&#x27;&#123;&quot;toUserId&quot;:&quot;&#x27; + $(&quot;#toUserId&quot;).val() + &#x27;&quot;,&quot;contentText&quot;:&quot;&#x27; + $(&quot;#contentText&quot;).val() + &#x27;&quot;&#125;&#x27;);        &#125;    &#125;&lt;/script&gt;&lt;body&gt;&lt;p&gt;【userId】：&lt;div&gt;&lt;input id=&quot;userId&quot; name=&quot;userId&quot; type=&quot;text&quot; value=&quot;10&quot;&gt;&lt;/div&gt;&lt;p&gt;【toUserId】：&lt;div&gt;&lt;input id=&quot;toUserId&quot; name=&quot;toUserId&quot; type=&quot;text&quot; value=&quot;20&quot;&gt;&lt;/div&gt;&lt;p&gt;【toUserId】：&lt;div&gt;&lt;input id=&quot;contentText&quot; name=&quot;contentText&quot; type=&quot;text&quot; value=&quot;hello websocket&quot;&gt;&lt;/div&gt;&lt;p&gt;【操作】：&lt;div&gt;&lt;a onclick=&quot;openSocket()&quot;&gt;开启socket&lt;/a&gt;&lt;/div&gt;&lt;p&gt;【操作】：&lt;div&gt;&lt;a onclick=&quot;sendMessage()&quot;&gt;发送消息&lt;/a&gt;&lt;/div&gt;&lt;/body&gt;&lt;/html&gt;

shiro 授权框架，个人理解主要适合单体应用，分布式应用和微服务架构模式下需要改造重新实现一些功能才能使用。 
# 基础环境

maven 依赖

&lt;dependency&gt;    &lt;groupId&gt;org.apache.shiro&lt;/groupId&gt;    &lt;artifactId&gt;shiro-spring-boot-starter&lt;/artifactId&gt;&lt;/dependency&gt;&lt;!-- shiro使用的是slf4j日志门面 --&gt;&lt;dependency&gt;    &lt;groupId&gt;log4j&lt;/groupId&gt;    &lt;artifactId&gt;log4j&lt;/artifactId&gt;&lt;/dependency&gt;

基本配置类

import org.apache.shiro.authc.credential.HashedCredentialsMatcher;import org.apache.shiro.authc.pam.AtLeastOneSuccessfulStrategy;import org.apache.shiro.authc.pam.ModularRealmAuthenticator;import org.apache.shiro.cache.MemoryConstrainedCacheManager;import org.apache.shiro.realm.AuthenticatingRealm;import org.apache.shiro.realm.AuthorizingRealm;import org.apache.shiro.spring.web.ShiroFilterFactoryBean;import org.apache.shiro.web.mgt.CookieRememberMeManager;import org.apache.shiro.web.mgt.DefaultWebSecurityManager;import org.apache.shiro.web.servlet.Cookie;import org.apache.shiro.web.servlet.SimpleCookie;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import java.util.Arrays;import java.util.HashMap;import java.util.Map;/** * @Description: * @Author: sunfy * @Date: 2020/10/19 上午11:18 */@Configurationpublic class shiroConfig &#123;    /**     * Realm  系统资源     * MyRealm类中已经注入，此处不需要重复     *     */    //    @Bean    //    public Realm myRealm() &#123;    //        return new MyRealm();    //    &#125;    /**     * SecurityManager 流程控制     * 构造方法的形式引入，创建对象的时候就可以引入Realm     */    @Bean    public DefaultWebSecurityManager mySecurityManager(AuthorizingRealm myRealm, AuthenticatingRealm mobileRealm) &#123;        DefaultWebSecurityManager securityManager = new DefaultWebSecurityManager();        //密码加密        HashedCredentialsMatcher matcher = new HashedCredentialsMatcher();        // 算法名        matcher.setHashAlgorithmName(&quot;MD5&quot;);        // 迭代次数        matcher.setHashIterations(3);//        private String hashAlgorithm;//        private int hashIterations;//        private boolean hashSalted;   已经过时//        private boolean storedCredentialsHexEncoded;  设置默认的        myRealm.setCredentialsMatcher(matcher);        mobileRealm.setCredentialsMatcher(matcher);        securityManager.setRealms(Arrays.asList(myRealm, mobileRealm));//        securityManager.setRealm(myRealm);        // 设置认证策略        ModularRealmAuthenticator authenticator = new ModularRealmAuthenticator();        // 设置认证策略为有一个成功即可        authenticator.setAuthenticationStrategy(new AtLeastOneSuccessfulStrategy());        // 设置所有的认证策略都返回成功//        authenticator.setAuthenticationStrategy(new AllSuccessfulStrategy());        // 设置第一个认证策略返回成功后不再认证后续的//        authenticator.setAuthenticationStrategy(new FirstSuccessfulStrategy());        authenticator.setRealms(Arrays.asList(myRealm, mobileRealm));        securityManager.setAuthenticator(authenticator);        CookieRememberMeManager cookieRememberMeManager = new CookieRememberMeManager();        Cookie cookie = new SimpleCookie(&quot;rememberMe&quot;);        cookie.setHttpOnly(true);        cookie.setMaxAge(5);        cookieRememberMeManager.setCookie(cookie);        /**         * 分布式环境需要自己改造以下功能         */        // 设置记住我功能        securityManager.setRememberMeManager(cookieRememberMeManager);        // session 共享//        securityManager.setSessionManager();        // 缓存        MemoryConstrainedCacheManager memoryConstrainedCacheManager = new MemoryConstrainedCacheManager();        securityManager.setCacheManager(memoryConstrainedCacheManager);        return securityManager;    &#125;    /**     * ShiroFilterFactoryBean 请求过滤器     */    @Bean    public ShiroFilterFactoryBean getShiroFilterFactoryBean(DefaultWebSecurityManager mySecurityManager)&#123;        ShiroFilterFactoryBean factoryBean = new ShiroFilterFactoryBean();        factoryBean.setSecurityManager(mySecurityManager);        // 配置路径经过过滤器        Map&lt;String, String&gt; fifterMap = new HashMap&lt;&gt;();        // key是ant路径，value配置shiro的默认过滤器        // shiro的默认过滤器，配置DefaultFilter        // anon(AnonymousFilter.class), 匿名过滤器        // authc(FormAuthenticationFilter.class), 认证（登录）使用        // authcBasic(BasicHttpAuthenticationFilter.class),  认证不通过跳转登录页        // authcBearer(BearerHttpAuthenticationFilter.class),        // logout(LogoutFilter.class),        // noSessionCreation(NoSessionCreationFilter.class),        // perms(PermissionsAuthorizationFilter.class),        // port(PortFilter.class),        // rest(HttpMethodPermissionFilter.class),        // roles(RolesAuthorizationFilter.class),        // ssl(SslFilter.class),        // user(UserFilter.class),        // invalidRequest(InvalidRequestFilter.class);//        fifterMap.put(&quot;/mobile/**&quot;, &quot;authc, perms[mobile]&quot;);        fifterMap.put(&quot;/salary/**&quot;, &quot;authc, perms[salary]&quot;);        // 相当与登出方法 使用shiro提供的logout过滤器        fifterMap.put(&quot;/common/logout&quot;, &quot;logout&quot;);        // 设置登录页        factoryBean.setLoginUrl(&quot;/index.html&quot;);        // 定制未授权页面        factoryBean.setUnauthorizedUrl(&quot;/common/unAuth&quot;);        // iml文件中进行相应的配置，也可以直接手动写//        factoryBean.setFilterChainDefinitions(&quot;/mobile/**=authc&quot;);        factoryBean.setFilterChainDefinitionMap(fifterMap);        return factoryBean;    &#125;&#125;
# 实现登录验证功能

创建 Realm 对象，继承  AuthorizingRealm
实现父类的方法

授权方法 doGetAuthorizationInfo
认证方法 doGetAuthenticationInfo



// Realm配置文件import com.sunfy.shiroWeb.bean.UserBean;import com.sunfy.shiroWeb.service.UserService;import org.apache.shiro.authc.*;import org.apache.shiro.authz.AuthorizationInfo;import org.apache.shiro.authz.SimpleAuthorizationInfo;import org.apache.shiro.realm.AuthorizingRealm;import org.apache.shiro.subject.PrincipalCollection;import org.apache.shiro.util.ByteSource;import org.slf4j.Logger;import org.slf4j.LoggerFactory;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.context.annotation.Configuration;/** * @Description: * @Author: sunfy * @Date: 2020/10/19 上午11:21 */@Configurationpublic class MyRealm extends AuthorizingRealm &#123;    @Autowired    private UserService userService;    private Logger logger = LoggerFactory.getLogger(MyRealm.class);    /**     * 授权     * @param principalCollection     * @return     */    @Override    protected AuthorizationInfo doGetAuthorizationInfo(PrincipalCollection principalCollection) &#123;        logger.info(&quot;&gt;&gt;&gt;entered MyRealm doGetAuthorizationInfo method&quot;);        SimpleAuthorizationInfo simpleAuthorizationInfo = new SimpleAuthorizationInfo();        // 获得当前用户        UserBean userBean = (UserBean) principalCollection.asList().get(0);        // 绑定角色和资源        simpleAuthorizationInfo.addRoles(userBean.getUserRoles());        simpleAuthorizationInfo.addStringPermissions(userBean.getUserPerms());        return simpleAuthorizationInfo;    &#125;    /**     * 认证     * @param authenticationToken     * @return     * @throws AuthenticationException     */    @Override    protected AuthenticationInfo doGetAuthenticationInfo(AuthenticationToken authenticationToken) throws AuthenticationException &#123;        logger.info(&quot;&lt;&lt;&lt;entered MyRealm doGetAuthenticationInfo method&quot;);        // 获得当前用户        UsernamePasswordToken userToken = (UsernamePasswordToken) authenticationToken;        String userName = userToken.getUsername();        // 获得数据库中密码，来跟当前用户进行比对，认证。        UserBean userBean = userService.queryUserByName(userName);        // 如果没有查到，没有这个用户        if (userBean == null) &#123;            // shiro判断 抛出 UnknownAccountException 异常提醒            return null;        &#125;        ByteSource salt = ByteSource.Util.bytes(&quot;salt&quot;);        // 返回 AuthenticationInfo 完成认证流程（密码比较认证shiro进行认证）        SimpleAuthenticationInfo simpleAuthenticationInfo =                new SimpleAuthenticationInfo(userBean, userBean.getUserPass(),salt,&quot;myRealm&quot;);        return simpleAuthenticationInfo;    &#125;&#125;
# 认证错误访问情况设置
设置登录页、登录成功也、未授权页面
// 设置登录页factoryBean.setLoginUrl(&quot;/index.html&quot;);// 定制未授权页面factoryBean.setUnauthorizedUrl(&quot;/common/unAuth&quot;);
登出
// 相当与登出方法 使用shiro提供的logout过滤器fifterMap.put(&quot;/common/logout&quot;, &quot;logout&quot;);
# 授权功能


控制主页上按钮的访问权限
currentUser.getPricipal()  来自  MyRealm  中 doGetAuthenticationInfo  认证返回的 simpleAuthenticationInfo  对象的第一个属性


控制后台资源路径的访问权限


方法 1：硬编码的方法，自行判断权限。
@RequestMapping(&quot;query&quot;)public String query()&#123;    Subject subject = SecurityUtils.getSubject();    if (subject.isPermitted(&quot;mobile&quot;)) &#123;        return &quot;mobile&quot;;    &#125;    return &quot;error&quot;;&#125;


方法 2：使用 shiro 提供的 perms  过滤器，集中配置权限信息
fifterMap.put(&quot;/mobile/**&quot;, &quot;authc, perms[mobile]&quot;);fifterMap.put(&quot;/salary/**&quot;, &quot;authc, perms[salary]&quot;);
错误补充机制：没有权限就会进入到 ShiroFilterFactoryBean  中配置的 UnauthorizedUrl


方法 3：使用 shiro 提供的注解，实现方法级别的权限控制。
@RequiresAuthentication 需要完成用户登录@RequiresGuest			未登录用户可以访问，登录用户不可访问@RequiresPermissions	需要有对应资源权限@RequiresRoles			需要有对应的角色@RequiresUser			需要完成用户登录并且实现了记住我功能
错误补充机制：没有权限会抛出异常（500 错误）
如果基本框架使用的是 Spring Boot 可以捕获异常处理：
import org.apache.shiro.authz.AuthorizationException;import org.springframework.web.bind.annotation.ExceptionHandler;import org.springframework.web.bind.annotation.RestControllerAdvice;/** * @Description: springBoot方式捕获异常处理 * @Author: sunfy * @Date: 2020/10/19 下午3:39 */@RestControllerAdvicepublic class MyExceptionHandler &#123;    @ExceptionHandler(AuthorizationException.class)    public Object unAuth()&#123;        return &quot;没有资源访问权限&quot;;    &#125;&#125;




# 密码加密
shiro 会获得一个 CredentialsMatcher  对象，来进行密码比对。
如果想使用 MD 5 加密，可以使用 HashedCredentialsMatcher ， Md5CredentialsMatcher  已经过期
//密码加密HashedCredentialsMatcher matcher = new HashedCredentialsMatcher();// 算法名matcher.setHashAlgorithmName(&quot;MD5&quot;);// 迭代次数matcher.setHashIterations(3);//        private String hashAlgorithm; 				算法名//        private int hashIterations; 					迭代次数//        private boolean hashSalted;   				已经过时//        private boolean storedCredentialsHexEncoded;  设置默认的myRealm.setCredentialsMatcher(matcher);
数据库数据加密方法
import org.apache.shiro.crypto.hash.SimpleHash;import org.apache.shiro.util.ByteSource;/** * @Description: 密码加密 * @Author: sunfy * @Date: 2020/10/19 下午4:40 */public class PasswordEncoder &#123;    public static String encoder(String password) &#123;        SimpleHash simpleHash = new SimpleHash(&quot;MD5&quot;, ByteSource.Util.bytes(password), ByteSource.Util.bytes(&quot;salt&quot;), 3);        return simpleHash.toString();    &#125;    public static void main(String[] args) &#123;        System.out.println(encoder(&quot;manager&quot;));    &#125;&#125;
# 多 Realm 认证
可用于实现用户名和手机号都可以登录。
org.apache.shiro.authz.ModularRealmAuthorizer    protected AuthenticationInfo doAuthenticate(AuthenticationToken authenticationToken) throws AuthenticationException &#123;        assertRealmsConfigured();        Collection&lt;Realm&gt; realms = getRealms();        if (realms.size() == 1) &#123;            return doSingleRealmAuthentication(realms.iterator().next(), authenticationToken);        &#125; else &#123;            return doMultiRealmAuthentication(realms, authenticationToken);        &#125;    &#125;
实现多个 Realm 完成不同的认证功能，通过增加一个 Realm，事项按照手机号也可以登录的功能
注意可以设置不同的认证策略：
// 创建认证策略ModularRealmAuthenticator authenticator = new ModularRealmAuthenticator();// 设置认证策略为至少有一个成功authenticator.setAuthenticationStrategy(new AtLeastOneSuccessfulStrategy());// 设置所有的认证策略都返回成功authenticator.setAuthenticationStrategy(new AllSuccessfulStrategy());// 设置第一个认证策略返回成功后不再认证后续的authenticator.setAuthenticationStrategy(new FirstSuccessfulStrategy());// 设置多个Realmauthenticator.setRealms(Arrays.asList(myRealm, mobileRealm));// 设置认证策略securityManager.setAuthenticator(authenticator);
# 记住我功能
